import React, { useState } from 'react';

function ReviewForm({ onSubmit, onCancel }) {
  const [reviewer, setReviewer] = useState('');
  const [comment, setComment] = useState('');
  const [rating, setRating] = useState(5);

  const handleSubmit = (e) => {
    e.preventDefault();
    onSubmit({ reviewer, comment, rating: parseInt(rating) });
    setReviewer('');
    setComment('');
    setRating(5);
  };

  return (
    <div className="card animate-fade-in">
      <div className="card-header">
        <div className="text-center">
          <div className="inline-flex items-center justify-center w-12 h-12 bg-primary rounded-xl mb-4">
            <span className="text-xl">✍️</span>
          </div>
          <h3 className="text-xl font-bold text-primary mb-2">Share Your Review</h3>
          <p className="text-secondary">Help others discover great books</p>
        </div>
      </div>

      <div className="card-body">
        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="form-label">Your Name</label>
            <input
              type="text"
              value={reviewer}
              onChange={(e) => setReviewer(e.target.value)}
              className="form-input"
              placeholder="Enter your name"
              required
            />
          </div>

          <div>
            <label className="form-label">Rating</label>
            <select
              value={rating}
              onChange={(e) => setRating(e.target.value)}
              className="form-select"
              required
            >
              <option value={5}>5 Stars - Excellent</option>
              <option value={4}>4 Stars - Very Good</option>
              <option value={3}>3 Stars - Good</option>
              <option value={2}>2 Stars - Fair</option>
              <option value={1}>1 Star - Poor</option>
            </select>
          </div>

          <div>
            <label className="form-label">Your Review</label>
            <textarea
              value={comment}
              onChange={(e) => setComment(e.target.value)}
              className="form-textarea"
              rows={5}
              placeholder="Share your thoughts about this book..."
              required
            />
          </div>

          <div className="flex gap-3">
            <button type="submit" className="btn btn-primary flex-1">
              <svg className="icon-sm mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
              </svg>
              Add Review
            </button>
            {onCancel && (
              <button type="button" onClick={onCancel} className="btn btn-secondary">
                Cancel
              </button>
            )}
          </div>
        </form>
      </div>
    </div>
  );
}

export default ReviewForm;
